	for i := range memo {
		memo[i] = make([][]int, target + 1)
		for j := range memo[i] {
			memo[i][j] = make([]int, maxOdd + 1)
			for k := range memo[i][j] {
				memo[i][j][k] = -1
			}
		}
	}

